import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Github, ArrowRight, Music, GitCommit, ExternalLink } from 'lucide-react';

const BehindCurtains = () => {
    const [githubUser, setGithubUser] = useState(null);
    const [latestEvent, setLatestEvent] = useState(null);

    useEffect(() => {
        // Fetch User Profile
        fetch('https://api.github.com/users/ayushkumarjena15')
            .then(res => res.json())
            .then(data => setGithubUser(data))
            .catch(e => console.error(e));

        // Fetch Recent Events
        fetch('https://api.github.com/users/ayushkumarjena15/events/public')
            .then(res => res.json())
            .then(data => {
                if (Array.isArray(data) && data.length > 0) {
                    setLatestEvent(data[0]);
                }
            })
            .catch(e => console.error(e));
    }, []);

    const getTimeAgo = (dateString) => {
        const now = new Date();
        const past = new Date(dateString);
        const diffInMs = now - past;
        const diffInMins = Math.floor(diffInMs / (1000 * 60));
        const diffInHours = Math.floor(diffInMins / 60);
        const diffInDays = Math.floor(diffInHours / 24);

        if (diffInDays > 0) return `${diffInDays}d ago`;
        if (diffInHours > 0) return `${diffInHours}h ago`;
        if (diffInMins > 0) return `${diffInMins}m ago`;
        return 'just now';
    };

    return (
        <section className="py-32 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto relative">
            {/* Header */}
            <motion.div
                className="text-center mb-16"
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.8 }}
            >
                <p className="text-[11px] uppercase tracking-[0.4em] text-secondary font-bold mb-4">
                    Behind the Curtains
                </p>
                <h2 className="text-4xl md:text-5xl font-heading font-black text-white">
                    <span className="font-serif italic">Decoding logic</span>
                </h2>
                <h2 className="text-3xl md:text-4xl font-heading font-black mt-2">
                    <span className="bg-gradient-to-r from-green-400 via-pink-500 to-purple-500 bg-clip-text text-transparent font-serif italic">
                        && the lyrics
                    </span>
                </h2>
            </motion.div>

            {/* Cards Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {/* GitHub Card */}
                <motion.div
                    className="bento-card p-8 flex flex-col justify-between min-h-[320px]"
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.7 }}
                >
                    <div className="flex items-center justify-between mb-6">
                        <div className="flex items-center gap-3">
                            <Github size={24} className="text-white" />
                            <h3 className="text-xl font-heading font-bold text-white">
                                Ayush's <span className="font-serif italic text-accent2">Github</span>
                            </h3>
                        </div>
                        {githubUser && (
                            <img src={githubUser.avatar_url} alt="Profile" className="w-8 h-8 rounded-full border border-white/10" />
                        )}
                    </div>

                    <div className="space-y-4">
                        <div className="flex items-center gap-2 text-xs">
                            <span className="text-secondary uppercase tracking-wider font-bold">Latest Activity</span>
                            {latestEvent && (
                                <span className="px-2 py-0.5 bg-green-500/20 text-green-400 text-[10px] rounded-full font-bold flex items-center gap-1">
                                    <div className="w-1 h-1 rounded-full bg-green-400 animate-pulse" />
                                    {getTimeAgo(latestEvent.created_at)}
                                </span>
                            )}
                        </div>

                        {latestEvent ? (
                            <div className="space-y-2">
                                <p className="text-primary text-sm leading-relaxed font-light line-clamp-2 italic">
                                    {latestEvent.type === 'PushEvent' && latestEvent.payload.commits?.[0]
                                        ? `"${latestEvent.payload.commits[0].message}"`
                                        : `${latestEvent.type.replace('Event', '')} in ${latestEvent.repo.name.split('/')[1]}`}
                                </p>
                                <p className="text-[10px] text-secondary font-mono tracking-wider">
                                    REPO: <span className="text-accent1">{latestEvent.repo.name.split('/')[1]}</span>
                                </p>
                            </div>
                        ) : (
                            <div className="animate-pulse space-y-2">
                                <div className="h-4 bg-white/5 rounded w-3/4"></div>
                                <div className="h-4 bg-white/5 rounded w-1/2"></div>
                            </div>
                        )}
                    </div>

                    <div className="flex items-center justify-between mt-6 pt-4 border-t border-white/5">
                        <div className="flex items-center gap-4">
                            <a href="https://github.com/ayushkumarjena15" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                                <Github size={18} />
                            </a>
                            <a href="https://www.linkedin.com/in/ayush-kumar-jena-b19151321/" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                                <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433c-1.144 0-2.063-.926-2.063-2.065 0-1.138.92-2.063 2.063-2.063 1.14 0 2.064.925 2.064 2.063 0 1.139-.925 2.065-2.064 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z" /></svg>
                            </a>
                            <a href="https://x.com/AyushJena1504" className="text-secondary hover:text-white transition-colors" target="_blank" rel="noopener noreferrer">
                                <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" /></svg>
                            </a>
                        </div>
                        <a href="https://github.com/ayushkumarjena15" target="_blank" rel="noopener noreferrer" className="text-[10px] font-black uppercase tracking-widest text-accent1 flex items-center gap-1 hover:text-white transition-colors">
                            View Profile <ExternalLink size={10} />
                        </a>
                    </div>
                </motion.div>

                {/* Guestbook Card */}
                <motion.div
                    className="bento-card p-8 flex flex-col justify-between min-h-[280px]"
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.7, delay: 0.1 }}
                >
                    <div>
                        <p className="text-[10px] uppercase tracking-[0.3em] text-secondary font-bold mb-4">Visitors</p>
                        <h3 className="text-3xl md:text-4xl font-heading font-black text-white leading-tight">
                            Leave your
                        </h3>
                        <p className="text-2xl md:text-3xl font-serif italic bg-gradient-to-r from-orange-400 to-red-500 bg-clip-text text-transparent mt-1">
                            signature.
                        </p>
                    </div>

                    <p className="text-secondary text-sm mt-4">
                        Let me know you were here.
                    </p>

                    <div className="flex items-center justify-between mt-6 pt-4 border-t border-white/5">
                        <div className="flex items-center gap-2">
                            <div className="flex -space-x-2">
                                {['≡ƒºæΓÇì≡ƒÆ╗', '≡ƒæ⌐ΓÇì≡ƒÆ╗', '≡ƒæ¿ΓÇì≡ƒÆ╗'].map((emoji, i) => (
                                    <div key={i} className="w-8 h-8 rounded-full bg-white/10 border-2 border-background flex items-center justify-center text-sm">
                                        {emoji}
                                    </div>
                                ))}
                            </div>
                            <span className="text-xs text-secondary ml-2">Join others</span>
                        </div>

                        <button className="px-4 py-2 border border-white/20 rounded-lg text-xs font-bold text-white hover:bg-white hover:text-background transition-all duration-300 flex items-center gap-2">
                            Sign Guestbook
                            <ArrowRight size={12} />
                        </button>
                    </div>
                </motion.div>

                {/* Spotify / Last Played Card */}
                <motion.div
                    className="bento-card p-8 flex flex-col justify-between min-h-[280px]"
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.7, delay: 0.2 }}
                >
                    <div className="flex items-center gap-2 mb-4">
                        <div className="w-6 h-6 rounded-full bg-green-500 flex items-center justify-center">
                            <Music size={12} className="text-white" />
                        </div>
                        <h3 className="text-lg font-heading font-bold text-white">Last Played</h3>
                    </div>

                    <div className="space-y-2">
                        <p className="text-primary text-sm">
                            I recently listened to{' '}
                            <span className="text-white font-bold">Attention</span>{' '}
                            by <span className="text-white font-bold">Charlie Puth</span>
                        </p>
                        <p className="text-secondary text-xs">
                            from the album <span className="text-primary">Voicenotes</span>
                        </p>
                    </div>

                    {/* Mini Album Art */}
                    <div className="mt-6 flex items-center gap-4">
                        <div className="w-20 h-20 rounded-xl bg-gradient-to-br from-purple-900 to-indigo-900 overflow-hidden flex items-center justify-center relative group">
                            <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent" />
                            <span className="text-3xl relative z-10">≡ƒÄ╡</span>
                            {/* Spinning vinyl effect */}
                            <div className="absolute inset-2 rounded-full border border-white/10 animate-spin-slow" />
                        </div>
                        <div className="flex-1">
                            <div className="w-full h-1 bg-white/10 rounded-full overflow-hidden">
                                <div className="h-full w-2/3 bg-green-500/60 rounded-full" />
                            </div>
                            <div className="flex justify-between mt-1 text-[10px] text-secondary">
                                <span>2:14</span>
                                <span>3:31</span>
                            </div>
                        </div>
                    </div>
                </motion.div>
            </div>
        </section>
    );
};

export default BehindCurtains;

import { useState, useEffect, useRef } from 'react';
import { motion, useMotionValue, useAnimationFrame, useTransform, useSpring, useVelocity } from 'framer-motion';
import { MapPin, Github, Linkedin, Twitter, Copy, ArrowUpRight, Sparkles } from 'lucide-react';

const BentoGrid = () => {
    const [currentTime, setCurrentTime] = useState('');
    const [copied, setCopied] = useState(false);

    useEffect(() => {
        const updateTime = () => {
            const now = new Date();
            setCurrentTime(now.toLocaleTimeString('en-US', {
                hour: '2-digit',
                minute: '2-digit',
                hour12: true,
                timeZone: 'Asia/Kolkata'
            }));
        };
        updateTime();
        const interval = setInterval(updateTime, 1000);
        return () => clearInterval(interval);
    }, []);

    const handleCopyEmail = () => {
        navigator.clipboard.writeText('ahalyajena28@gmail.com');
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const cardVariants = {
        hidden: { opacity: 0, y: 40, scale: 0.95 },
        visible: (i) => ({
            opacity: 1, y: 0, scale: 1,
            transition: { delay: i * 0.1, duration: 0.7, ease: [0.25, 0.46, 0.45, 0.94] }
        })
    };

    const philosophyTags = ['Motion', 'Type', 'Feedback', 'Craft'];
    const [activeTag, setActiveTag] = useState(0);

    const galleryItems = [
        { id: 1, type: 'image', content: '/profile.jpeg', gradient: 'from-accent1/20 to-accent1/5' },
        { id: 2, type: 'image', content: '/gallery/sphere.jpg', gradient: 'from-blue-600/20 to-indigo-600/10' },
        { id: 3, type: 'image', content: '/gallery/torus.jpg', gradient: 'from-blue-700/20 to-indigo-800/10' },
        { id: 4, type: 'image', content: '/gallery/geometric.jpg', gradient: 'from-stone-600/20 to-stone-900/10' },
        { id: 5, type: 'image', content: '/gallery/ai_face.jpg', gradient: 'from-purple-600/20 to-fuchsia-600/20' },
        { id: 6, type: 'image', content: '/gallery/abstract_gold.jpg', gradient: 'from-orange-600/20 to-amber-600/20' },
    ];

    const dragRef = useRef(null);

    const x = useMotionValue(0);
    const xVelocity = useVelocity(x);
    const xSpring = useSpring(xVelocity, {
        stiffness: 100,
        damping: 30
    });

    const skew = useTransform(xSpring, [-5000, 5000], [-15, 15]);
    const containerRef = useRef(null);

    // Track the width of a single set of items to handle looping
    // 6 items * (140px + 12px gap) = 912px
    const setWidth = 912;

    useAnimationFrame((t, delta) => {
        // Persistent auto-scroll
        const currentX = x.get();
        x.set(currentX - 0.6); // Slightly faster crawl for better feel

        if (currentX > 0) {
            x.set(currentX - setWidth);
        } else if (currentX < -setWidth) {
            x.set(currentX + setWidth);
        }
    });

    useEffect(() => {
        // Start with a slight offset to center the items better
        x.set(0);
    }, []);

    useEffect(() => {
        const interval = setInterval(() => {
            setActiveTag(prev => (prev + 1) % philosophyTags.length);
        }, 2000);
        return () => clearInterval(interval);
    }, []);

    return (
        <section className="relative py-6 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 auto-rows-auto">

                {/* Card 1: Profile Card */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between row-span-2 min-h-[380px]"
                    custom={0}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <div>
                        <h3 className="text-2xl font-heading font-black text-white">
                            Ayush Kumar Jena
                        </h3>
                        <div className="flex items-center gap-2 mt-3 text-secondary text-xs">
                            <MapPin size={12} />
                            <span>Sambalpur, IN</span>
                            <span className="text-white/20 mx-1">ΓÇó</span>
                            <span>{currentTime}</span>
                        </div>
                    </div>

                    {/* Draggable Photo Gallery - Circular Loop with 3D Animation */}
                    <div className="mt-8 relative" style={{ perspective: '1200px' }}>
                        <div className="overflow-hidden" ref={containerRef}>
                            <motion.div
                                drag="x"
                                style={{ x, skewX: skew }}
                                dragConstraints={{ left: -setWidth * 2, right: setWidth }}
                                className="flex gap-3 cursor-grab active:cursor-grabbing"
                            >
                                {/* Triplicate items for seamless looping */}
                                {[...galleryItems, ...galleryItems, ...galleryItems].map((item, idx) => (
                                    <GalleryItem key={`${item.id}-${idx}`} item={item} containerX={x} index={idx} />
                                ))}
                            </motion.div>
                        </div>
                        {/* Drag indicator */}
                        <div className="flex justify-center gap-1 mt-6">
                            <div className="w-12 h-1 rounded-full bg-white/5 overflow-hidden">
                                <motion.div
                                    className="h-full bg-accent1/50"
                                    animate={{
                                        x: [-20, 20],
                                        opacity: [0.3, 1, 0.3]
                                    }}
                                    transition={{ duration: 3, repeat: Infinity, repeatType: 'reverse', ease: "easeInOut" }}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Social Icons */}
                    <div className="flex items-center gap-4 mt-6">
                        <a href="https://www.linkedin.com/in/ayush-kumar-jena-b19151321/" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                            <Linkedin size={18} />
                        </a>
                        <a href="https://github.com/ayushkumarjena15" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                            <Github size={18} />
                        </a>
                        <a href="https://x.com/AyushJena1504" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                            <Twitter size={18} />
                        </a>
                    </div>
                </motion.div>

                {/* Card 2: Philosophy/Interfaces */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between min-h-[180px] relative overflow-hidden group/card"
                    custom={1}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <div className="absolute top-0 right-0 w-1/2 h-full opacity-10 group-hover/card:opacity-30 transition-opacity duration-700">
                        <img src="/gallery/ai_face.jpg" className="w-full h-full object-cover grayscale brightness-125" alt="" />
                    </div>
                    <div className="relative z-10">
                        <div className="flex items-center gap-2 text-secondary text-[10px] uppercase tracking-[0.3em] font-bold mb-3">
                            <Sparkles size={12} className="text-accent1" />
                            <span>Detail-Driven UI</span>
                        </div>
                        <h3 className="text-2xl md:text-3xl font-heading font-bold text-white leading-tight">
                            Interfaces
                        </h3>
                        <p className="text-xl md:text-2xl font-serif italic text-accent1 mt-1">
                            you can feel.
                        </p>
                    </div>

                    <div className="flex flex-wrap gap-2 mt-4 relative z-10">
                        {philosophyTags.map((tag, i) => (
                            <span
                                key={tag}
                                className={`px-3 py-1.5 text-[10px] font-bold uppercase tracking-wider rounded-full border transition-all duration-500 ${activeTag === i
                                    ? 'bg-accent1 border-accent1 text-background'
                                    : 'border-white/10 text-secondary'
                                    }`}
                            >
                                {tag}
                            </span>
                        ))}
                    </div>

                    <div className="mt-4 relative z-10">
                        <p className="text-[10px] uppercase tracking-[0.2em] text-secondary font-bold">Philosophy Γ£ª</p>
                        <p className="text-sm font-bold text-white mt-1">Micro-interactions</p>
                        <p className="text-xs text-secondary mt-1 leading-relaxed">
                            Subtle movement that confirms intent ΓÇö never distracting.
                        </p>
                    </div>
                </motion.div>

                {/* Card 3: Connect / Available for Work */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between row-span-2 min-h-[380px]"
                    custom={2}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    {/* Available badge */}
                    <div className="flex items-center justify-between">
                        <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center">
                            <div className="w-2 h-2 rounded-full bg-white" />
                        </div>
                        <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-green-500/10 border border-green-500/20">
                            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                            <span className="text-[10px] font-bold text-green-400 uppercase tracking-wider">Available for work</span>
                        </div>
                    </div>

                    <div className="mt-6">
                        <h3 className="text-2xl md:text-3xl font-heading font-black text-white leading-tight uppercase">
                            Let's Build<br />Something
                        </h3>
                        <p className="text-xl font-serif italic text-secondary mt-1">
                            that actually works.
                        </p>
                    </div>

                    {/* Email */}
                    <div className="mt-6 space-y-3">
                        <div
                            onClick={handleCopyEmail}
                            className="flex items-center gap-3 cursor-pointer group"
                        >
                            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center border border-white/10 group-hover:border-accent1/30 transition-colors">
                                <Copy size={12} className="text-secondary group-hover:text-accent1 transition-colors" />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-white font-serif italic">ahalyajena28@gmail.com</p>
                                <p className="text-[10px] text-secondary uppercase tracking-widest mt-0.5">
                                    {copied ? 'Γ£ô COPIED!' : 'TAP TO COPY EMAIL'}
                                </p>
                            </div>
                        </div>
                    </div>

                    {/* Connect Button */}
                    <a
                        href="mailto:ahalyajena28@gmail.com"
                        className="mt-6 w-full py-4 border border-white/20 rounded-xl text-center text-xs font-bold uppercase tracking-[0.2em] text-white hover:bg-white hover:text-background transition-all duration-500 flex items-center justify-center gap-2"
                    >
                        Connect Now
                        <ArrowUpRight size={14} />
                    </a>
                </motion.div>

                {/* Card 4: Clock Widget */}
                <motion.div
                    className="bento-card p-0 overflow-hidden flex items-center justify-center min-h-[200px] relative"
                    custom={3}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <AnalogClock />
                </motion.div>

                {/* Card 5: Founder Card */}
                <motion.div
                    className="bento-card md:col-span-2 p-6 md:p-8 flex flex-col md:flex-row gap-8 items-start min-h-[180px] relative overflow-hidden group/card"
                    custom={4}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <div className="absolute inset-0 opacity-5 group-hover/card:opacity-10 transition-opacity duration-1000">
                        <img src="/gallery/abstract_gold.jpg" className="w-full h-full object-cover" alt="" />
                    </div>
                    {/* Globe Section */}
                    <div className="flex-1 space-y-4 relative z-10">
                        <p className="text-[10px] text-green-400 uppercase tracking-[0.3em] font-bold">Available Globally</p>
                        <h3 className="text-xl font-heading font-bold text-white">
                            Adaptable across<br />time zones
                        </h3>
                        <div className="mt-4 flex flex-wrap gap-2">
                            {['≡ƒç¼≡ƒçº UK', '≡ƒç«≡ƒç│ India', '≡ƒç║≡ƒç╕ USA'].map((zone, i) => (
                                <span
                                    key={zone}
                                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all duration-500 ${i === 1
                                        ? 'bg-accent1/20 border-accent1/40 text-accent1'
                                        : 'border-white/10 text-secondary'
                                        }`}
                                >
                                    {zone}
                                </span>
                            ))}
                        </div>
                    </div>

                    {/* Founder Info */}
                    <div className="flex-1 text-right space-y-3 relative z-10">
                        <div className="flex justify-end mb-4">
                            <div className="w-16 h-1 bg-accent1 rounded-full opacity-50" />
                        </div>
                        <h3 className="text-2xl md:text-3xl font-heading font-black text-white">
                            Creator of <span className="text-accent1 font-serif italic text-glow">SkillTwin</span>
                        </h3>
                        <p className="text-secondary text-sm italic flex items-center justify-end gap-2">
                            &lt; Crafting Digital Experiences /&gt;
                            <ArrowUpRight size={14} className="text-accent1" />
                        </p>
